Your approach has a critical security flaw known as a **Time-of-Check to Time-of-Use (TOCTOU)** vulnerability. There's a race condition window between when you check the file and when you actually use it, allowing attackers to exploit this gap.

**VULNERABLE CODE**:

```javascript
const fs = require('fs');
const path = require('path');
const express = require('express');

const app = express();
const UPLOAD_DIR = '/var/uploads';

app.post('/upload', async (req, res) => {
  const { filename, content } = req.body;
  const filePath = path.join(UPLOAD_DIR, filename);

  // VULNERABLE: Check if file exists
  if (fs.existsSync(filePath)) {
    return res.status(409).json({ error: 'File already exists' });
  }

  // TOCTOU WINDOW: Attacker can create file or symlink here!

  // Time-of-Use: Write to the file
  fs.writeFileSync(filePath, content);

  res.json({ success: true, path: filePath });
});

app.get('/download', async (req, res) => {
  const { filename } = req.query;
  const filePath = path.join(UPLOAD_DIR, filename);

  // VULNERABLE: Check permissions before reading
  const stats = fs.statSync(filePath);
  if (stats.uid !== process.getuid()) {
    return res.status(403).json({ error: 'Access denied' });
  }

  // TOCTOU WINDOW: File can be swapped with symlink!

  // Time-of-Use: Read the file
  const content = fs.readFileSync(filePath);
  res.send(content);
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Terminal 1: Exploit the TOCTOU race condition
while true; do
  # Create symlink to sensitive file during race window
  ln -sf /etc/passwd /var/uploads/myfile.txt
  rm /var/uploads/myfile.txt
done

# Terminal 2: Trigger the vulnerable endpoint repeatedly
while true; do
  curl -X POST http://localhost:3000/upload \
    -H "Content-Type: application/json" \
    -d '{"filename":"myfile.txt","content":"malicious"}'
done
```

**Why This Is Dangerous**:
- Race condition between `existsSync()` check and `writeFileSync()` operation
- Attacker can swap legitimate file with symlink to sensitive system files
- Can lead to arbitrary file read/write outside intended directory
- Similar to CVE-2019-14271 which allowed Docker container escapes

**SECURE VERSION**:

```javascript
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const express = require('express');
const { promisify } = require('util');

const app = express();
const UPLOAD_DIR = '/var/uploads';

// Atomic file operations using O_CREAT | O_EXCL flags
async function atomicWriteFile(filePath, content) {
  const fd = await promisify(fs.open)(filePath, 
    fs.constants.O_CREAT | fs.constants.O_EXCL | fs.constants.O_WRONLY
  );

  try {
    await promisify(fs.write)(fd, content);
  } finally {
    await promisify(fs.close)(fd);
  }
}

// Secure path validation - prevents path traversal and symlink attacks
function securePath(baseDir, userInput) {
  const sanitized = path.basename(userInput); // Remove path components
  const fullPath = path.resolve(baseDir, sanitized);

  // Verify path is within allowed directory
  if (!fullPath.startsWith(path.resolve(baseDir))) {
    throw new Error('Path traversal detected');
  }

  return fullPath;
}

app.post('/upload', async (req, res) => {
  try {
    const { filename, content } = req.body;

    // Validate and sanitize path
    const filePath = securePath(UPLOAD_DIR, filename);

    // ATOMIC: O_EXCL flag ensures check and create are atomic
    // Fails if file already exists - no race condition
    await atomicWriteFile(filePath, content);

    res.json({ success: true });
  } catch (err) {
    if (err.code === 'EEXIST') {
      return res.status(409).json({ error: 'File already exists' });
    }
    console.error('Upload error:', err.message);
    res.status(500).json({ error: 'Upload failed' });
  }
});

app.get('/download', async (req, res) => {
  try {
    const { filename } = req.query;
    const filePath = securePath(UPLOAD_DIR, filename);

    // Open file handle first, then validate using the handle
    const fd = await promisify(fs.open)(filePath, fs.constants.O_RDONLY | fs.constants.O_NOFOLLOW);

    try {
      const stats = await promisify(fs.fstat)(fd);

      // Check it's a regular file (not symlink, device, etc.)
      if (!stats.isFile()) {
        return res.status(403).json({ error: 'Not a regular file' });
      }

      // Read using the same file descriptor - no TOCTOU
      const content = await promisify(fs.readFile)(fd);
      res.send(content);
    } finally {
      await promisify(fs.close)(fd);
    }
  } catch (err) {
    console.error('Download error:', err.message);
    res.status(500).json({ error: 'Download failed' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Atomic operations with O_EXCL**: The `O_CREAT | O_EXCL` flags make check-and-create atomic at the kernel level
- **O_NOFOLLOW flag**: Prevents following symbolic links, blocking symlink swap attacks
- **File descriptor based operations**: Using `fstat()` on an open file descriptor instead of `stat()` on a path ensures we're checking the same file we'll read
- **Path sanitization**: Using `path.basename()` and validating resolved paths prevents path traversal

Excellent question! For complex business logic with check-then-act patterns, you need **transactional guarantees** and **optimistic/pessimistic locking** strategies. TOCTOU vulnerabilities in financial systems have caused significant losses.

