const express = require('express');
const { Pool } = require('pg');
const crypto = require('crypto');
const Redis = require('ioredis');
const winston = require('winston');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const redis = new Redis(process.env.REDIS_URL);

// Structured logging for audit trail
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Distributed lock for cross-process synchronization
class DistributedLock {
  constructor(redis) {
    this.redis = redis;
  }

  async acquire(resource, ttlMs = 5000) {
    const lockId = crypto.randomUUID();
    const key = `lock:${resource}`;

    // SET NX with expiry - atomic lock acquisition
    const result = await this.redis.set(key, lockId, 'PX', ttlMs, 'NX');

    if (result === 'OK') {
      return { acquired: true, lockId, key };
    }
    return { acquired: false };
  }

  async release(key, lockId) {
    // Lua script ensures atomic check-and-delete
    const script = `
      if redis.call('get', KEYS[1]) == ARGV[1] then
        return redis.call('del', KEYS[1])
      else
        return 0
      end
    `;
    await this.redis.eval(script, 1, key, lockId);
  }
}

const distributedLock = new DistributedLock(redis);

// PATTERN 1: Optimistic Locking for financial transactions
async function transferFunds(fromAccountId, toAccountId, amount, userId) {
  const client = await pool.connect();
  const idempotencyKey = crypto.randomUUID();

  try {
    await client.query('BEGIN');

    // Check for duplicate transaction (idempotency)
    const dupCheck = await client.query(
      'SELECT id FROM transactions WHERE idempotency_key = $1',
      [idempotencyKey]
    );
    if (dupCheck.rows.length > 0) {
      await client.query('ROLLBACK');
      return { success: false, error: 'Duplicate transaction' };
    }

    // OPTIMISTIC LOCKING: SELECT FOR UPDATE locks the rows
    // Prevents concurrent modifications during transaction
    const fromAccount = await client.query(
      `SELECT id, balance, version FROM accounts 
       WHERE id = $1 FOR UPDATE`,
      [fromAccountId]
    );

    const toAccount = await client.query(
      `SELECT id, balance, version FROM accounts 
       WHERE id = $1 FOR UPDATE`,
      [toAccountId]
    );

    if (fromAccount.rows.length === 0 || toAccount.rows.length === 0) {
      await client.query('ROLLBACK');
      return { success: false, error: 'Account not found' };
    }

    const sourceBalance = parseFloat(fromAccount.rows[0].balance);

    // Business rule check happens WITHIN the lock
    if (sourceBalance < amount) {
      await client.query('ROLLBACK');
      logger.warn('Insufficient funds', {
        userId,
        fromAccountId,
        requested: amount,
        available: sourceBalance
      });
      return { success: false, error: 'Insufficient funds' };
    }

    // Atomic updates with version check (double protection)
    const updateSource = await client.query(
      `UPDATE accounts SET 
         balance = balance - $1,
         version = version + 1,
         updated_at = NOW()
       WHERE id = $2 AND version = $3
       RETURNING balance`,
      [amount, fromAccountId, fromAccount.rows[0].version]
    );

    if (updateSource.rowCount === 0) {
      await client.query('ROLLBACK');
      return { success: false, error: 'Concurrent modification detected' };
    }

    await client.query(
      `UPDATE accounts SET 
         balance = balance + $1,
         version = version + 1,
         updated_at = NOW()
       WHERE id = $2`,
      [amount, toAccountId]
    );

    // Record transaction for audit
    await client.query(
      `INSERT INTO transactions 
       (idempotency_key, from_account, to_account, amount, user_id, created_at)
       VALUES ($1, $2, $3, $4, $5, NOW())`,
      [idempotencyKey, fromAccountId, toAccountId, amount, userId]
    );

    await client.query('COMMIT');

    logger.info('Transfer completed', {
      idempotencyKey,
      fromAccountId,
      toAccountId,
      amount,
      userId,
      newBalance: updateSource.rows[0].balance
    });

    return { success: true, transactionId: idempotencyKey };

  } catch (err) {
    await client.query('ROLLBACK');
    logger.error('Transfer failed', { error: err.message, userId });
    throw err;
  } finally {
    client.release();
  }
}

// PATTERN 2: Distributed locking for quota management
async function updateUserQuota(userId, bytesToAdd) {
  const lockResource = `quota:${userId}`;
  const lock = await distributedLock.acquire(lockResource, 10000);

  if (!lock.acquired) {
    logger.warn('Failed to acquire quota lock', { userId });
    return { success: false, error: 'Resource busy, try again' };
  }

  try {
    const client = await pool.connect();

    try {
      await client.query('BEGIN');

      // Get current quota with row lock
      const result = await client.query(
        `SELECT used_bytes, max_bytes FROM user_quotas 
         WHERE user_id = $1 FOR UPDATE`,
        [userId]
      );

      if (result.rows.length === 0) {
        await client.query('ROLLBACK');
        return { success: false, error: 'User quota not found' };
      }

      const { used_bytes, max_bytes } = result.rows[0];
      const newUsed = parseInt(used_bytes) + bytesToAdd;

      // Check quota within lock - no TOCTOU
      if (newUsed > parseInt(max_bytes)) {
        await client.query('ROLLBACK');
        logger.info('Quota exceeded', { userId, requested: bytesToAdd, used: used_bytes, max: max_bytes });
        return { success: false, error: 'Quota exceeded' };
      }

      // Update atomically
      await client.query(
        `UPDATE user_quotas 
         SET used_bytes = $1, updated_at = NOW() 
         WHERE user_id = $2`,
        [newUsed, userId]
      );

      await client.query('COMMIT');

      return { success: true, newUsedBytes: newUsed };

    } finally {
      client.release();
    }
  } finally {
    // CRITICAL: Always release lock
    await distributedLock.release(lock.key, lock.lockId);
  }
}

