	ErrAccessDenied    = errors.New("access denied")
	ErrSymlinkDetected = errors.New("symlink not allowed")
)

type SecureFileReader struct {
	baseDir     string
	allowedExts []string
	maxFileSize int64
	logger      *slog.Logger
	fileLocks   sync.Map
