		baseDir:     baseDir,
		allowedExts: allowedExts,
		maxFileSize: maxSize,
		logger:      logger,
	}
}

// SecureReadFile implements TOCTOU-safe file reading
func (sfr *SecureFileReader) SecureReadFile(ctx context.Context, userID, requestedPath string) ([]byte, error) {
	// Step 1: Validate and canonicalize path BEFORE any filesystem access
	cleanPath := filepath.Clean(requestedPath)
	if strings.Contains(cleanPath, "..") {
		sfr.logger.Warn("path traversal attempt",
			"user_id", userID,
			"path", requestedPath)
		return nil, ErrInvalidPath
	}

	fullPath := filepath.Join(sfr.baseDir, cleanPath)

	// Verify path is still within base directory after Join
	if !strings.HasPrefix(fullPath, sfr.baseDir+string(os.PathSeparator)) {
		sfr.logger.Warn("path escape attempt",
			"user_id", userID,
			"resolved_path", fullPath)
		return nil, ErrInvalidPath
	}

	// Validate file extension
	ext := strings.ToLower(filepath.Ext(fullPath))
	if !sfr.isAllowedExtension(ext) {
		return nil, ErrInvalidPath
	}

	// Step 2: Use file descriptor-based operations (TOCTOU-safe)
	// Open with O_NOFOLLOW to prevent symlink attacks
	fd, err := syscall.Open(fullPath, syscall.O_RDONLY|syscall.O_NOFOLLOW, 0)
	if err != nil {
		if errors.Is(err, syscall.ELOOP) {
			sfr.logger.Warn("symlink attack detected",
				"user_id", userID,
				"path", fullPath)
			return nil, ErrSymlinkDetected
		}
		return nil, fmt.Errorf("failed to open file: %w", err)
	}

	// Convert to os.File for easier handling
	file := os.NewFile(uintptr(fd), fullPath)
	defer file.Close()

	// Step 3: All checks now use the FILE DESCRIPTOR, not the path
	// This eliminates TOCTOU because we're operating on the same inode
	var stat syscall.Stat_t
	if err := syscall.Fstat(fd, &stat); err != nil {
		return nil, fmt.Errorf("failed to stat file: %w", err)
	}

	// Verify it's a regular file using the file descriptor
	if stat.Mode&syscall.S_IFMT != syscall.S_IFREG {
		sfr.logger.Warn("non-regular file access attempt",
			"user_id", userID,
			"path", fullPath,
			"mode", stat.Mode)
		return nil, ErrAccessDenied
	}

