	if stat.Size > sfr.maxFileSize {
		return nil, fmt.Errorf("file too large: %d bytes", stat.Size)
	}

	// Verify file ownership/permissions using file descriptor
	if stat.Uid == 0 && stat.Mode&syscall.S_IWOTH != 0 {
		sfr.logger.Error("suspicious file permissions",
			"path", fullPath,
			"uid", stat.Uid,
			"mode", stat.Mode)
		return nil, ErrAccessDenied
	}

	// Step 4: Read from the same file descriptor
	content := make([]byte, stat.Size)
	_, err = io.ReadFull(file, content)
	if err != nil {
		return nil, fmt.Errorf("failed to read file: %w", err)
	}

	// Audit log for successful access
	sfr.logger.Info("file accessed",
		"user_id", userID,
		"path", fullPath,
		"size", stat.Size,
		"timestamp", time.Now().UTC())

	return content, nil
}

func (sfr *SecureFileReader) isAllowedExtension(ext string) bool {
	for _, allowed := range sfr.allowedExts {
		if ext == allowed {
			return true
		}
	}
	return false
}

// SecureAtomicWrite implements TOCTOU-safe atomic file writing
func (sfr *SecureFileReader) SecureAtomicWrite(ctx context.Context, userID, targetPath string, content []byte) error {
	cleanPath := filepath.Clean(targetPath)
	fullPath := filepath.Join(sfr.baseDir, cleanPath)

	// Validate path stays within base directory
	if !strings.HasPrefix(fullPath, sfr.baseDir+string(os.PathSeparator)) {
		return ErrInvalidPath
	}

	// Create temporary file in same directory (ensures same filesystem)
	tempFile, err := os.CreateTemp(filepath.Dir(fullPath), ".tmp-")
	if err != nil {
		return fmt.Errorf("failed to create temp file: %w", err)
	}
	tempPath := tempFile.Name()

	// Cleanup on any error
	success := false
	defer func() {
		if !success {
			os.Remove(tempPath)
		}
	}()

	// Write content to temp file
	if _, err := tempFile.Write(content); err != nil {
		tempFile.Close()
		return fmt.Errorf("failed to write temp file: %w", err)
	}

	// Sync to ensure data is on disk before rename
	if err := tempFile.Sync(); err != nil {
		tempFile.Close()
		return fmt.Errorf("failed to sync temp file: %w", err)
	}
	tempFile.Close()

	// Set proper permissions before rename
	if err := os.Chmod(tempPath, 0644); err != nil {
		return fmt.Errorf("failed to set permissions: %w", err)
	}

	// Atomic rename - this is the TOCTOU-safe operation
	// Either the old file exists or the new file exists, never partial state
	if err := os.Rename(tempPath, fullPath); err != nil {
		return fmt.Errorf("failed to rename file: %w", err)
	}

	success = true
	sfr.logger.Info("file written atomically",
		"user_id", userID,
		"path", fullPath,
		"size", len(content))

	return nil
}
