const fsFstat = promisify(fs.fstat);
const fsClose = promisify(fs.close);
const fsFtruncate = promisify(fs.ftruncate);
const fsFsync = promisify(fs.fsync);

class SecureFileHandler extends EventEmitter {
  constructor(options = {}) {
    super();
    this.baseDir = options.baseDir || '/var/app/data';
    this.lockTimeout = options.lockTimeout || 30000;
    this.activeLocks = new Map();
