  async acquireLock(filePath, lockId) {
    const start = Date.now();

    while (this.activeLocks.has(filePath)) {
      if (Date.now() - start > this.lockTimeout) {
        throw new SecureFileError('LOCK_TIMEOUT', 'Failed to acquire lock');
      }
      await new Promise(resolve => setTimeout(resolve, 100));
    }

    this.activeLocks.set(filePath, { lockId, timestamp: Date.now() });
  }

  releaseLock(filePath, lockId) {
    const lock = this.activeLocks.get(filePath);
    if (lock && lock.lockId === lockId) {
      this.activeLocks.delete(filePath);
    }
  }

