    // File owner has full access
    if (stats.uid === userId) return true;

    // Check group permissions
    const mode = stats.mode;
    if (operation === 'read') {
      return (mode & fs.constants.S_IROTH) !== 0;
    }
    if (operation === 'write') {
      return (mode & fs.constants.S_IWOTH) !== 0;
    }
    return false;
  }
}

