		baseDir:     baseDir,
		auditLogger: auditLog,
	}
}

// ServeSecureFile eliminates TOCTOU by using file descriptor operations
func (s *SecureFileServer) ServeSecureFile(w http.ResponseWriter, r *http.Request, userID string) {
	ctx, cancel := context.WithTimeout(r.Context(), 30*time.Second)
	defer cancel()

	requestedPath := r.URL.Query().Get("file")
	if requestedPath == "" {
		s.auditLog(userID, requestedPath, "DENIED", "Empty filename")
		http.Error(w, "File not specified", http.StatusBadRequest)
		return
	}

	// Sanitize and resolve path
	safePath, err := s.resolveSafePath(requestedPath)
	if err != nil {
		s.auditLog(userID, requestedPath, "DENIED", "Path traversal attempt")
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	// SECURE: Open file first, THEN check permissions on the open fd
	// This eliminates TOCTOU because we operate on the same file object
	file, err := os.OpenFile(safePath, os.O_RDONLY|syscall.O_NOFOLLOW, 0)
	if err != nil {
		if os.IsNotExist(err) {
			s.auditLog(userID, safePath, "DENIED", "File not found")
			http.Error(w, "File not found", http.StatusNotFound)
		} else if os.IsPermission(err) {
			s.auditLog(userID, safePath, "DENIED", "OS permission denied")
			http.Error(w, "Access denied", http.StatusForbidden)
		} else {
			s.auditLog(userID, safePath, "ERROR", err.Error())
			http.Error(w, "Internal error", http.StatusInternalServerError)
		}
		return
	}
	defer file.Close()

	// Get file info from the OPEN file descriptor (not the path)
	// This is immune to TOCTOU because we're checking the actual open file
	fileInfo, err := file.Stat()
	if err != nil {
		s.auditLog(userID, safePath, "ERROR", "Failed to stat open fd")
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Verify it's a regular file (not symlink, device, etc.)
	if !fileInfo.Mode().IsRegular() {
		s.auditLog(userID, safePath, "DENIED", "Not a regular file")
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	// Application-level permission check using fd
	if !s.checkUserPermission(userID, file, fileInfo) {
		s.auditLog(userID, safePath, "DENIED", "User permission denied")
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// Verify file hasn't been modified during our checks (defense in depth)
	var statBuf unix.Stat_t
	if err := unix.Fstat(int(file.Fd()), &statBuf); err != nil {
		s.auditLog(userID, safePath, "ERROR", "Fstat failed")
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// Set security headers
	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", fmt.Sprintf("attachment; filename=%q", filepath.Base(safePath)))
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))

	s.auditLog(userID, safePath, "GRANTED", fmt.Sprintf("Size: %d bytes", fileInfo.Size()))

	// Stream file with context cancellation support
	done := make(chan struct{})
	go func() {
		defer close(done)
		io.Copy(w, file)
	}()

	select {
	case <-ctx.Done():
		s.auditLog(userID, safePath, "CANCELLED", "Request timeout")
		return
	case <-done:
		return
	}
}

