    return res.status(409).json({ error: 'File already exists' });
  } catch (err) {
    // File doesn't exist, proceed
  }

  // RACE CONDITION WINDOW: Attacker can create symlink at targetPath!

  // Step 3: Move uploaded file to target
  await fs.promises.rename(req.file.path, targetPath);

  res.json({ success: true, path: targetPath });
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker script running in parallel with upload
while true; do
  # Replace user directory with symlink to sensitive location
  rm -rf /var/www/uploads/attacker_id
  ln -s /etc /var/www/uploads/attacker_id

  # Or create symlink at target path to overwrite arbitrary files
  ln -s /etc/passwd /var/www/uploads/attacker_id/malicious.txt
done
```

**Why This Is Dangerous**:
- The check (access) and use (rename) are separate operations with a time gap
- Attacker can win the race by replacing directory with symlink between check and use
- Can write files anywhere on filesystem the server process has access to
- Can overwrite system files like /etc/passwd, crontab, or application configs

**SECURE VERSION**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');
const multer = require('multer');
const crypto = require('crypto');

const app = express();
const upload = multer({ dest: '/tmp/uploads/' });

const UPLOAD_DIR = '/var/www/uploads';

// Security: Resolve real path and validate it's within allowed directory
function isPathWithinDirectory(targetPath, allowedDir) {
  const resolvedTarget = path.resolve(targetPath);
  const resolvedAllowed = path.resolve(allowedDir);
  return resolvedTarget.startsWith(resolvedAllowed + path.sep);
}

// Security: Generate unpredictable filename to prevent symlink placement
function generateSecureFilename(originalName) {
  const ext = path.extname(originalName);
  const randomName = crypto.randomBytes(16).toString('hex');
  return `${randomName}${ext}`;
}

app.post('/upload', upload.single('file'), async (req, res) => {
  const userId = req.user.id;

  // Security: Validate userId format to prevent path traversal
  if (!/^[a-zA-Z0-9_-]+$/.test(userId)) {
    return res.status(400).json({ error: 'Invalid user ID' });
  }

  const userDir = path.join(UPLOAD_DIR, userId);

  // Security: Use unpredictable filename
  const secureFilename = generateSecureFilename(req.file.originalname);
  const targetPath = path.join(userDir, secureFilename);

  // Security: Validate resolved path is within upload directory
  if (!isPathWithinDirectory(targetPath, UPLOAD_DIR)) {
    console.error(`Path traversal attempt: ${targetPath}`);
    return res.status(403).json({ error: 'Invalid path' });
  }

  try {
    // Security: Create directory with O_EXCL equivalent
    await fs.promises.mkdir(userDir, { recursive: true, mode: 0o755 });

    // Security: Use atomic operation with O_EXCL flag
    // This fails if file exists or is symlink - no race condition
    const fileHandle = await fs.promises.open(targetPath, 
      fs.constants.O_WRONLY | fs.constants.O_CREAT | fs.constants.O_EXCL,
      0o644
    );

    // Security: Read source and write atomically through handle
    const sourceData = await fs.promises.readFile(req.file.path);
    await fileHandle.write(sourceData);
    await fileHandle.close();

    // Clean up temp file
    await fs.promises.unlink(req.file.path);

    res.json({ success: true, filename: secureFilename });
  } catch (err) {
    console.error(`Upload failed: ${err.message}`);
    if (err.code === 'EEXIST') {
      return res.status(409).json({ error: 'File conflict' });
    }
    return res.status(500).json({ error: 'Upload failed' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Atomic file creation**: Using O_EXCL flag ensures the file is created exclusively, failing if it exists or is a symlink
- **Path validation after resolution**: Checking the resolved path prevents symlink-based path traversal
- **Unpredictable filenames**: Random filenames make it impossible for attackers to pre-create symlinks at known paths
- **Single atomic operation**: Combining check and use into one syscall eliminates the race window

Read-modify-write operations are particularly susceptible to TOCTOU attacks. The solution is to use file locking, atomic operations, and transactional patterns.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { promisify } = require('util');

// Use proper-lockfile for cross-platform file locking
const lockfile = require('proper-lockfile');

const app = express();

const DATA_DIR = '/var/app/data';

class SecureFileOperations {
  constructor(baseDir) {
    this.baseDir = path.resolve(baseDir);
  }

  // Validate path is within allowed directory using realpath
  async validatePath(filePath) {
    const resolved = path.resolve(filePath);

    // Check logical path first
    if (!resolved.startsWith(this.baseDir + path.sep)) {
      throw new Error('Path traversal detected');
    }

    // If file exists, verify real path (follows symlinks)
    try {
      const realPath = await fs.promises.realpath(resolved);
      if (!realPath.startsWith(this.baseDir + path.sep)) {
        throw new Error('Symlink escape detected');
      }
      return realPath;
    } catch (err) {
      if (err.code === 'ENOENT') {
        // File doesn't exist yet, that's OK for creation
        return resolved;
      }
      throw err;
    }
  }

  // Atomic read-modify-write with file locking
  async atomicUpdate(filePath, updateFn) {
    const validPath = await this.validatePath(filePath);
    let release;

    try {
      // Acquire exclusive lock - blocks other processes
      release = await lockfile.lock(validPath, {
        stale: 10000,      // Lock expires after 10s
        retries: {
          retries: 5,
          minTimeout: 100,
          maxTimeout: 1000
        }
      });

      // Open file with exclusive access via file descriptor
      const fd = await fs.promises.open(validPath, 'r+');

      try {
        // Verify file hasn't been replaced (check inode)
        const stats = await fd.stat();
        const pathStats = await fs.promises.lstat(validPath);

        if (stats.ino !== pathStats.ino) {
          throw new Error('File was replaced during operation');
        }

        // Read current content
        const content = await fd.readFile('utf8');

        // Apply update function
        const newContent = await updateFn(content);

        // Truncate and write atomically through same fd
        await fd.truncate(0);
        await fd.write(newContent, 0, 'utf8');
        await fd.sync();  // Ensure data is flushed to disk

        return newContent;
      } finally {
        await fd.close();
      }
    } finally {
      if (release) {
        await release();
      }
    }
  }

  // Atomic write using temp file + rename pattern
  async atomicWrite(filePath, content) {
    const validPath = await this.validatePath(filePath);
    const dir = path.dirname(validPath);
    const tempPath = path.join(dir, `.tmp.${crypto.randomBytes(8).toString('hex')}`);

    try {
      // Write to temp file first
      await fs.promises.writeFile(tempPath, content, {
        mode: 0o644,
        flag: 'wx'  // Exclusive create
      });

      // Ensure data is on disk
      const fd = await fs.promises.open(tempPath, 'r');
      await fd.sync();
      await fd.close();

      // Atomic rename - this is the key!
      // On POSIX systems, rename() is atomic
      await fs.promises.rename(tempPath, validPath);

      // Sync directory to ensure rename is persisted
      const dirFd = await fs.promises.open(dir, 'r');
      await dirFd.sync();
      await dirFd.close();

    } catch (err) {
      // Clean up temp file on error
      try {
        await fs.promises.unlink(tempPath);
      } catch (unlinkErr) {
        // Ignore cleanup errors
      }
      throw err;
    }
  }

  // Secure file read with symlink protection
  async secureRead(filePath) {
    const validPath = await this.validatePath(filePath);

    // Open with O_NOFOLLOW equivalent behavior
    const fd = await fs.promises.open(validPath, 'r');

    try {
      // Verify it's a regular file, not symlink
      const stats = await fd.stat();
      if (!stats.isFile()) {
        throw new Error('Not a regular file');
      }

      return await fd.readFile('utf8');
    } finally {
      await fd.close();
    }
  }
}

// Rate limiting and monitoring
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

const fileOps = new SecureFileOperations(DATA_DIR);

// Audit logging
function auditLog(action, userId, filePath, success, details = {}) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    action,
    userId,
    filePath,
    success,
    ...details
  };
  console.log(JSON.stringify(logEntry));
  // In production: send to SIEM/log aggregation
}

app.use(express.json());
app.use(limiter);

// Atomic increment counter example
app.post('/api/counter/:name/increment', async (req, res) => {
  const userId = req.user?.id || 'anonymous';
  const counterName = req.params.name;

  // Validate counter name
  if (!/^[a-zA-Z0-9_-]+$/.test(counterName)) {
    auditLog('increment', userId, counterName, false, { reason: 'invalid_name' });
    return res.status(400).json({ error: 'Invalid counter name' });
  }

  const filePath = path.join(DATA_DIR, `counters/${counterName}.json`);

  try {
    const newContent = await fileOps.atomicUpdate(filePath, (content) => {
      const data = JSON.parse(content);
      data.value = (data.value || 0) + 1;
      data.lastModified = new Date().toISOString();
      data.modifiedBy = userId;
      return JSON.stringify(data, null, 2);
    });

    auditLog('increment', userId, counterName, true);
    res.json(JSON.parse(newContent));

  } catch (err) {
    auditLog('increment', userId, counterName, false, { error: err.message });

    if (err.message.includes('ENOENT')) {
      return res.status(404).json({ error: 'Counter not found' });
    }
    if (err.message.includes('symlink') || err.message.includes('traversal')) {
      return res.status(403).json({ error: 'Access denied' });
    }

    console.error('Counter increment failed:', err);
    res.status(500).json({ error: 'Operation failed' });
  }
});

// Health check endpoint for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.listen(3000, () => {
  console.log('Secure file service running on port 3000');
});
```

**Defense in Depth Layers**:

1. **File Locking Layer**:
```javascript
// Using proper-lockfile ensures exclusive access
const release = await lockfile.lock(filePath, {
  stale: 10000,  // Auto-release stale locks
  retries: 5     // Retry on contention
});
try {
  // Critical section - only one process at a time
} finally {
  await release();
}
```

2. **Atomic Operations Layer**:
```javascript
// Rename is atomic on POSIX - either completes fully or not at all
await fs.promises.writeFile(tempPath, content);
await fs.promises.rename(tempPath, targetPath);  // Atomic!
```

3. **Symlink Protection Layer**:
```javascript
// Verify real path matches expected path
const realPath = await fs.promises.realpath(filePath);
if (!realPath.startsWith(allowedDir)) {
  throw new Error('Symlink escape detected');
}
```

**Additional Protections**:
- **Inode verification**: Check that file descriptor points to same inode as path to detect file replacement
- **O_EXCL for creation**: Prevents race conditions when creating new files
- **fsync() after writes**: Ensures data durability before proceeding
- **Directory sync after rename**: Ensures rename operation is persisted
- **Stale lock detection**: Prevents deadlocks from crashed processes
- **Audit logging**: All file operations logged for security monitoring
- **Rate limiting**: Prevents attackers from rapid-fire race condition attempts
